frappe.ui.form.on('Asset', {
    onload: function(frm) {
        frm.set_query('custodian', function() {
            if (frm.doc.company) {
                return {
                    filters: {
                        company: frm.doc.company
                    }
                };
            }
        });
    },
    company: function(frm) {
        frm.set_query('custodian', function() {
            if (frm.doc.company) {
                return {
                    filters: {
                        company: frm.doc.company
                    }
                };
            }
