frappe.ui.form.on('Vehicle Log', {
  onload: function(frm) {
    frappe.call({
      method: "frappe.client.get",
      args: {
        doctype: "User",
        name: frappe.session.user,
      },
      callback: function(r) {
        if (r.message && r.message.location) {
          const user_location = r.message.location;

          frm.set_query("license_plate", function() {
            let allowed_locations = [];

           if (user_location === "GUYONG") {
              allowed_locations = ["GUYONG", "EDSA", "MC1"];
            } else {
              allowed_locations = [user_location];
            }

            return {
              filters: [
                ["Vehicle", "location", "in", allowed_locations]
              ]
            };
          });
        }
      }
    });
  }
});

frappe.ui.form.on('Asset', {
    refresh: function(frm) {
        frm.set_query('custom_section', function() {
            return {
                filters: {
                    location: frm.doc.location // adjust if different fieldname
                }
            };
        });
    },

    location: function(frm) {
        frm.trigger('refresh');  // Refresh the query when location changes
    }
});

frappe.listview_settings['Asset'] = {
    onload(listview) {
        listview.page.add_inner_button('Print Asset Tags', () => {
            const selected = listview.get_checked_items();

            if (selected.length === 0) {
                frappe.msgprint(__('Please select at least one asset.'));
                return;
            }

            const asset_names = selected.map(row => row.name);

            frappe.call({
                method: 'frappe.desk.page.server_script.server_script.run',
                args: {
                    script_name: 'Multiple Asset Tag',
                    asset_names: JSON.stringify(asset_names)
                },
                callback: function(r) {
                    const data = r.message;

                    let html = '';
                    data.forEach(asset => {
                        html += `
                            <div style="border:1px solid #000; padding:10px; margin:5px; width:45%; display:inline-block;">
                                <b>${asset.name}</b><br>
                                ${asset.item_name}<br>
                                Brand: ${asset.custom_brand_name}<br>
                                Model: ${asset.custom_model}<br>
                                Serial: ${asset.custom_serial_no}<br>
                                Cost: ₱${asset.gross_purchase_amount}
                            </div>
                        `;
                    });

                    const win = window.open('', '_blank');
                    win.document.write(`<html><head><title>Asset Tags</title></head><body>${html}</body></html>`);
                    win.document.close();
                    win.print();
                }
            });
        });
    }
};

