frappe.ui.form.on('Job Requisition', {
    refresh(frm) {
        // Delay to ensure ERPNext adds workflow buttons first
        setTimeout(() => {
            set_dynamic_workflow_actions(frm);
        }, 50);
    },

    department(frm) {
        // Recalculate buttons whenever department changes
        set_dynamic_workflow_actions(frm);
    },

    workflow_state(frm) {
        // Recalculate buttons when workflow state changes
        set_dynamic_workflow_actions(frm);
    }
});

// ================================
// Helper functions
// ================================
function set_dynamic_workflow_actions(frm) {
    // Remove all existing action buttons first
    frm.page.clear_actions();

    // Track which custom buttons we already added
    frm.custom_action_added = new Set();

    const dept = frm.doc.department || "";
    const state = frm.doc.workflow_state || "";

    if (!state) return;

    // Define department groups
    const finance_depts = ["Finance - MC", "Finance CANDC - MC", "Finance Cost - MC", 
                "Finance General - MC", "Finance Audit - MC", "Finance Asset - MC", 
                "Finance MIS - MC", "Finance Provincial - MC", "Finance - QC", 
                "Finance CANDC - QC", "Finance Cost - QC", "Finance General - QC", 
                "Finance Audit - QC", "Finance Asset - QC", "Finance MIS - QC", 
                "Finance Provincial - QC"];
    const sales_depts = ["Sales - QC", "Sales - MC", "Sales Provincial - MC"];
    const proc_depts = ["Procurement - QC", "Procurement - MC"];

    // -------------------
    // Add buttons per workflow state
    // -------------------
    if (state === "Draft") {
        add_custom_action(frm, "Submit for Approval");
    }

    else if (state === "For Approval") {
        if (finance_depts.includes(dept)) {
            add_custom_action(frm, "For BCC Approval");
        } else if (sales_depts.includes(dept)) {
            add_custom_action(frm, "For VP Sales Approval");
        } else if (proc_depts.includes(dept)) {
            add_custom_action(frm, "For VP Procurement Approval");
        } else {
            add_custom_action(frm, "Approve");
        }
    }

    else if (state === "For BCC Approval") {
        add_custom_action(frm, "Approve");
    }

    else if (state === "For VP Sales Approval") {
        add_custom_action(frm, "Approve");
    }

    else if (state === "For VP Procurement Approval") {
        add_custom_action(frm, "Approve");
    }

    else if (state === "Approved") {
        add_custom_action(frm, "Acknowledge");
    }

    else if (state === "Acknowledged") {
        add_custom_action(frm, "Cancel");
    }
}

// ================================
// Function to add a custom workflow button
// ================================
function add_custom_action(frm, action_name) {
    if (frm.custom_action_added.has(action_name)) return;

    frm.page.add_action_item(action_name, () => {
        frappe.xcall("frappe.model.workflow.apply_workflow", {
            doc: frm.doc,
            action: action_name
        }).then(() => frm.reload_doc());
    });

    frm.custom_action_added.add(action_name);
}

frappe.ui.form.on("Staffing Plan", {
    refresh: function(frm) {
        // Only run if there are child rows
        if(frm.doc.staffing_details && frm.doc.staffing_details.length > 0) {
            frm.doc.staffing_details.forEach(function(d, idx) {
                frappe.call({
                    method: "qcmc_logic.overrides.StaffingPlanOverrides.get_current_count",
                    args: {
                        docname: frm.doc.name,     // may be "new-xxxx" for unsaved docs
                        child_idx: idx,
                        data: frm.doc              // send entire doc JSON so Python can read it
                    },
                    callback: function(r) {
                        if (r.message !== undefined) {
                            frappe.model.set_value(d.doctype, d.name, "current_count", r.message);
                            frappe.show_alert(`Current count: ${r.message}`);
                        }
                    }
                });
            });
        }
    }
});

frappe.ui.form.on("Delivery Trip", {
  refresh(frm) {
    // Hide "Notify Customers via Email" button
    frm.page.remove_inner_button("Notify Customers via Email");
  }
});

frappe.ui.form.on("Delivery Trip", {
  refresh: async function (frm) {
    cleanup_trip_map(frm);

    frm.remove_custom_button("Optimize Route");
    frm.remove_custom_button("Calculate Estimated Arrival Times");
    frm.remove_custom_button("Show Map (Leaflet)");

    const autoRender = should_autorender_map(frm);
    if (autoRender) {
      setTimeout(async () => {
        try {
          await load_leaflet_once();
          await render_trip_map(frm);
        } catch (e) {
          console.warn("Auto-render map failed:", e);
        }
      }, 150);
    }

    if (frm.doc.docstatus === 0) {
      inject_inline_buttons(frm);
    }
  }
});

function inject_inline_buttons(frm) {
  frm.fields_dict.delivery_stops.$wrapper.find(".custom-inline-btns").remove();

  const $btn_row = $(`
    <div class="custom-inline-btns" style="margin-top: 10px; display: flex; gap: 8px;">
      <button class="btn btn-primary btn-sm btn-optimize-osrm">
        <i class="fa fa-map-marker"></i> Optimize Route (OSRM)
      </button>
      <button class="btn btn-default btn-sm btn-eta-osrm">
        <i class="fa fa-clock-o"></i> Calculate ETAs (OSRM)
      </button>
    </div>
  `);

  frm.fields_dict.delivery_stops.$wrapper.append($btn_row);

  $btn_row.find(".btn-optimize-osrm").on("click", async function () {
    frappe.show_alert({ message: "Optimizing route...", indicator: "blue" });
    await frappe.call({
      method: "route_optimizer.api.delivery_trip.optimize_route_osrm",
      args: { delivery_trip: frm.doc.name }
    });
    await frm.reload_doc();
    await load_leaflet_once();
    await render_trip_map(frm);
    frappe.show_alert({ message: "Route optimized (OSRM) and map updated.", indicator: "green" });
  });

  $btn_row.find(".btn-eta-osrm").on("click", async function () {
    frappe.show_alert({ message: "Calculating ETAs...", indicator: "blue" });
    await frappe.call({
      method: "route_optimizer.api.delivery_trip.calculate_etas_osrm",
      args: { delivery_trip: frm.doc.name }
    });
    await frm.reload_doc();
    frappe.show_alert({ message: "ETAs updated (OSRM).", indicator: "green" });
  });
}

function cleanup_trip_map(frm) {
  if (frm.__trip_map_instance) {
    try { frm.__trip_map_instance.remove(); } catch (e) {}
    frm.__trip_map_instance = null;
  }
  if (frm.fields_dict.custom_route_map) {
    frm.fields_dict.custom_route_map.$wrapper.empty();
  }
}

function should_autorender_map(frm) {
  if ((frm.doc.custom_route_geojson || "").trim()) return true;
  if (frm.doc.custom_location) return true;
  const stops = frm.doc.delivery_stops || [];
  return stops.some(r => {
    const lat = toNum(r.custom_latitude);
    const lng = toNum(r.custom_longitude);
    return lat !== null && lng !== null;
  });
}

async function load_leaflet_once() {
  if (window.L) return;
  await new Promise((resolve, reject) => {
    const css = document.createElement("link");
    css.rel = "stylesheet";
    css.href = "https://unpkg.com/leaflet@1.9.4/dist/leaflet.css";
    css.onload = resolve; css.onerror = reject;
    document.head.appendChild(css);
  });
  await new Promise((resolve, reject) => {
    const script = document.createElement("script");
    script.src = "https://unpkg.com/leaflet@1.9.4/dist/leaflet.js";
    script.onload = resolve; script.onerror = reject;
    document.head.appendChild(script);
  });
}

function toNum(v) {
  if (v === null || v === undefined || v === "") return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function make_visited_icon() {
  return L.divIcon({
    className: "",
    html: `<div style="
      width: 18px; height: 18px;
      background: #28a745;
      border: 3px solid #fff;
      border-radius: 50%;
      box-shadow: 0 0 4px rgba(0,0,0,0.4);
    "></div>`,
    iconSize: [18, 18],
    iconAnchor: [9, 9],
    popupAnchor: [0, -10]
  });
}

async function get_stop_latlng(row) {
  let lat = toNum(row.custom_latitude);
  let lng = toNum(row.custom_longitude);
  if (lat !== null && lng !== null) return { lat, lng };

  const addr_name = row.address_name || row.address;
  if (!addr_name) return null;

  try {
    const addr = await frappe.db.get_doc("Address", addr_name);
    const loc_name = addr.custom_location;
    if (!loc_name) {
      console.warn(`Address ${addr_name} has no linked Location (custom_location).`);
      return null;
    }
    const loc = await frappe.db.get_doc("Location", loc_name);
    lat = toNum(loc.latitude);
    lng = toNum(loc.longitude);
    if (lat !== null && lng !== null) return { lat, lng };
    console.warn(`Location ${loc_name} missing latitude/longitude.`);
  } catch (e) {
    console.warn("Failed to resolve Address/Location for stop:", addr_name, e);
  }
  return null;
}

async function render_trip_map(frm) {
  if (!frm.fields_dict.custom_route_map) {
    frappe.msgprint("Missing field: custom_route_map (HTML field) on Delivery Trip.");
    return;
  }

  const map_id = `trip_map_${frm.doc.name.replace(/[^a-zA-Z0-9_]/g, "_")}`;

  frm.fields_dict.custom_route_map.$wrapper.html(`
    <div id="${map_id}" style="height: 420px; border-radius: 10px; overflow:hidden;"></div>
  `);

  if (frm.__trip_map_instance) {
    frm.__trip_map_instance.remove();
    frm.__trip_map_instance = null;
  }

  const map = L.map(map_id).setView([14.5995, 120.9842], 11);
  frm.__trip_map_instance = map;

  L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
    maxZoom: 19,
    attribution: "&copy; OpenStreetMap contributors"
  }).addTo(map);

  const bounds = [];

  if (frm.doc.custom_location) {
    try {
      const loc = await frappe.db.get_doc("Location", frm.doc.custom_location);
      const slat = toNum(loc.latitude);
      const slng = toNum(loc.longitude);
      if (slat !== null && slng !== null) {
        L.marker([slat, slng]).addTo(map).bindPopup(`<strong>START</strong><br>${frm.doc.custom_location}`);
        bounds.push([slat, slng]);
      }
    } catch (e) {
      console.warn("Failed to fetch Location:", frm.doc.custom_location, e);
    }
  }

  const stops = frm.doc.delivery_stops || [];
  for (let i = 0; i < stops.length; i++) {
    const row = stops[i];
    const ll = await get_stop_latlng(row);
    const addrLabel = row.address_name || row.address || "";
    const isVisited = row.visited === 1 || row.visited === true;

    if (ll) {
      const marker = isVisited
        ? L.marker([ll.lat, ll.lng], { icon: make_visited_icon() })
        : L.marker([ll.lat, ll.lng]);

      marker.addTo(map).bindPopup(
        `<strong>#${i + 1} ${row.customer || ""}</strong><br>${addrLabel}<br>
        <span style="color: ${isVisited ? "#28a745" : "#888"};">
          ${isVisited ? "✅ Delivered" : "⏳ Not yet delivered"}
        </span>`
      );
      bounds.push([ll.lat, ll.lng]);
    }
  }

  if (bounds.length) map.fitBounds(bounds, { padding: [20, 20] });

  if ((frm.doc.custom_route_geojson || "").trim()) {
    try {
      const geo = JSON.parse(frm.doc.custom_route_geojson);
      L.geoJSON(geo).addTo(map);
    } catch (e) {
      console.error("Invalid custom_route_geojson:", e);
      frappe.msgprint("Route GeoJSON is invalid. Check console for details.");
    }
  }
}

