frappe.ui.form.on('Item', {
    refresh(frm) {

        async function display_image_from_base64(base64_data, filename) {
            if(frm.fields_dict.custom_code_display) {
                frm.fields_dict.custom_code_display.$wrapper.html(`
                    <div style="text-align:center;">
                        <img src="${base64_data}" alt="Code" style="max-width:200px; margin-bottom:10px;" />
                        <br>
                        <button class="btn btn-primary btn-sm" id="download-btn">Download</button>
                    </div>
                `);

                frm.fields_dict.custom_code_display.$wrapper.find("#download-btn").on("click", function() {
                    const link = document.createElement('a');
                    link.href = base64_data;
                    link.download = filename;
                    link.click(); // automatic download
                });
            }
        }

        // --- Generate QR Code ---
        frm.add_custom_button('Generate QR Code', function() {
            if (!frm.doc.item_code) {
                frappe.msgprint("Item Code is required to generate QR Code.");
                return;
            }

            frappe.call({
                method: "qcmc_logic.api.generate_code.generate_qr",
                args: { item_code: frm.doc.item_code },
                callback: function(r) {
                    display_image_from_base64(r.message, `${frm.doc.item_code}_QR.png`);
                }
            });

        }, __("Actions"));

        // --- Generate Barcode ---
        frm.add_custom_button('Generate Barcode', function() {
            if (!frm.doc.item_code) {
                frappe.msgprint("Item Code is required to generate Barcode.");
                return;
            }

            frappe.call({
                 method: "qcmc_logic.api.generate_code.generate_barcode",
                args: { item_code: frm.doc.item_code },
                callback: function(r) {
                    display_image_from_base64(r.message, `${frm.doc.item_code}_Barcode.png`);
                }
            });

        }, __("Actions"));

    }
});

