function set_required_item_filter(frm) {
    frm.fields_dict["required_items"].grid.get_field("item_code").get_query = function(doc, cdt, cdn) {
        return {
            filters: { "item_group": "Toolroom" }
        };
    };
}

frappe.ui.form.on('Sales Order', {
	refresh: function(frm) {
		// your code here
		frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Company',
                filters: { 'is_group': 0 },
                fields: ['name'],
                limit_page_length: 1  // Get the first company that is not a group
            },
            callback: function(response) {
                if (response.message && response.message.length > 0) {
                    frm.set_value('company', response.message[0].name);
                    frm.set_value('custom_abbr', response.message[0].abbr);
                }
            }
        });


		frm.set_query("company", function() {
            return {
                filters: {
                    "is_group": 0  // Filters only non-group companies
                }
            };
        });
	},
    company: function(frm) {  // Trigger when company field changes
        if (frm.doc.company) {
            frappe.call({
                method: 'frappe.client.get_value',
                args: {
                    doctype: 'Company',
                    filters: { 'name': frm.doc.company },
                    fieldname: 'abbr'
