frappe.ui.form.on('Stock Entry Reference Detail', {
    fetch_items: function (frm, cdt, cdn) {
        const row = locals[cdt][cdn];

        if (!row.reference_type || !row.reference_name) {
            frappe.msgprint("Please select Reference Type and Reference Name in the parent form.");
            return;
        }
        if (!frm.doc.from_warehouse || !frm.doc.to_warehouse) {
            frappe.msgprint("Please default Source and Target Warehouse.");
            return;
        }

        frappe.call({
            method: "StockEntryReferenceFetchItems", // Adjust to match your Python method path
            args: {
                reference_type: row.reference_type,
                reference_name: row.reference_name,
                company: frm.doc.company
            },
            callback: function (r) {
                if (!r.data || r.data.length === 0) {
                    frappe.msgprint("No items found.");
                    return;
                }

                const items = r.data;

                const table_html = `
                    <table class="table table-bordered">
                        <thead>
                            <tr>
                                <th><input type="checkbox" id="select_all_items" /></th>
                                <th>Item Code</th>
                                <th>Item Name</th>
                                <th>Qty</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${items.map((item, idx) => `
                                <tr>
                                    <td><input type="checkbox" class="select-item" data-idx="${idx}" /></td>
                                    <td><a href="/app/item/${item.item_code}" target="_blank">${item.item_code}</a></td>
                                    <td>${item.item_name}</td>
                                    <td>${item.qty}</td>
                                </tr>
                            `).join('')}
                        </tbody>
                    </table>
                `;

                const dialog = new frappe.ui.Dialog({
                    title: 'Select Items to Add',
                    fields: [
                        {
                            fieldtype: 'HTML',
                            fieldname: 'items_html',
                            options: table_html
                        }
                    ],
                    primary_action_label: 'Add Selected Items',
                    primary_action() {
                        const selected_items = [];
                        const checkboxes = dialog.$wrapper.find('.select-item:checked');

                        checkboxes.each(function () {
                            const idx = parseInt($(this).data('idx'));
                            if (!isNaN(idx)) {
                                selected_items.push(items[idx]);
                            }
                        });

                        selected_items.forEach(item => {
                            const child = frm.add_child("items");
                            child.item_code = item.item_code;
                            child.item_name = item.item_name;
                            child.qty = item.qty;
                            child.transfer_qty = item.qty;
                            child.stock_uom = item.stock_uom;
                            child.conversion_factor = item.conversion_factor;
                            child.s_warehouse = frm.doc.from_warehouse;
                            child.t_warehouse = frm.doc.to_warehouse || '';
                        });

                        frm.refresh_field("items");
                        dialog.hide();
                    }
                });

                dialog.show();

                // Handle "Select All"
                setTimeout(() => {
                    dialog.$wrapper.find('#select_all_items').on('change', function () {
                        const checked = $(this).is(':checked');
                        dialog.$wrapper.find('.select-item').prop('checked', checked);
                    });
                }, 300);
            }
        });
    }
});

frappe.ui.form.on('Stock Entry Reference Detail', {
    fetch_items: function (frm, cdt, cdn) {
        const row = locals[cdt][cdn];

