                                            <th>Item Code</th>
                                            <th>Item Name</th>
                                            <th>Qty</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        ${items.map((item, idx) => `
                                            <tr>
                                                <td><input type="checkbox" class="select-item" data-idx="${idx}" /></td>
                                                <td><a href="/app/item/${escapeHTML(item.item_code)}" target="_blank">${escapeHTML(item.item_code)}</a></td>
                                                <td>${escapeHTML(item.item_name)}</td>
                                                <td>${escapeHTML(item.qty)}</td>
                                            </tr>
                                        `).join('')}
                                    </tbody>
                                </table>
                            `;

                            const dialog = new frappe.ui.Dialog({
                                title: 'Select Items to Add',
                                fields: [
                                    {
                                        fieldtype: 'HTML',
                                        fieldname: 'items_html',
                                        options: table_html
                                    }
                                ],
                                primary_action_label: 'Add Selected Items',
                                primary_action() {
                                    const selected_items = [];
                                    const checkboxes = dialog.$wrapper.find('.select-item:checked');

                                    checkboxes.each(function () {
                                        const idx = parseInt($(this).data('idx'));
                                        if (!isNaN(idx)) {
                                            selected_items.push(items[idx]);
                                        }
                                    });

                                    selected_items.forEach(item => {
                                        const child = frm.add_child("transfer_items");
                                        child.item_code = item.item_code;
                                        child.item_name = item.item_name;
                                        child.issued_qty = item.qty;
                                        child.uom = item.stock_uom;
                                        child.reference_doc = row.reference_name || '';
                                    });

                                    frm.refresh_field("transfer_items");
                                    dialog.hide();
                                }
                            });

                            dialog.show();

                            setTimeout(() => {
                                dialog.$wrapper.find('#select_all_items').on('change', function () {
