function set_custom_doc_code(frm) {
    let role_list = frappe.user_roles;
    let code = null;

    frappe.call({
        method: "frappe.client.get_value",
        args: {
            doctype: "User",
            filters: { name: frappe.session.user },
            fieldname: "location"
        },
        callback: function(r) {
            if (!r.message) return;
            let user_location = r.message.custom_location;

            // --- Company Rules ---
            if (frm.doc.company === "MCY") {
                code = "MCY";
            } 
            // --- Role + Company ---
            else if (role_list.includes("WH_PR_EDSA_Lv1")) {
                if (frm.doc.company === "QC Styropackaging Corporation") {
                    code = "12";
                } else if (frm.doc.company === "Multiplast Corporation") {
                    code = "12M";
                }
            }
            // --- Location Valenzuela ---
            else if (user_location === "Valenzuela") {
                if (role_list.includes("Stockroom_PR_MC_lv1")) {
                    code = "99RR";
                } else if (role_list.includes("RMFS_PR_MC")) {
                    code = "99R";
                }
            }
            // --- Location Guyong ---
            else if (user_location === "Guyong") {
                if (role_list.includes("RMFS_PR_QC_lv1")) {
                    code = "35R";
                } else if (role_list.includes("Stockroom_PR_QC_lv1")) {
                    code = "35";
                } else if (role_list.includes("Motorpool_PR_QC_lv1")) {
                    code = "MWRR";
                }
            }
            // --- Location Sta Clara ---
            else if (user_location === "Sta Clara") {
                if (role_list.includes("Stockroom_PR_QC_lv1")) {
                    code = "33";
                } else if (role_list.includes("RMFS_PR_QC_lv1")) {
                    code = "33R";
                }
            }

            // Set value
            if (code) {
                frm.set_value("custom_doc_code", code);
            } else {
                frm.set_value("custom_doc_code", "");
            }
        }
    });
}

