function show_convert_dialog(frm) {
    // Prepare item rows (only items not yet converted)
    const items = frm.doc.items
        .filter(i => !i.custom_converted_item)
        .map(i => {
            return `
                <tr>
                    <td><input type="checkbox" class="convert-check" data-item="${i.name}"></td>
                    <td>${i.item_code}</td>
                    <td>${i.item_name}</td>
                    <td>${i.qty}</td>
                    <td>${i.uom}</td>
                </tr>
            `;
        }).join('');

    if (!items) {
        frappe.msgprint(__('All items are already converted.'));
        return;
    }

    const d = new frappe.ui.Dialog({
        title: 'Select Items to Convert to Partner PR',
        size: 'large',
        fields: [
            {
                fieldname: 'html_table',
                fieldtype: 'HTML',
                options: `
                    <table class="table table-bordered table-sm">
                        <thead>
                            <tr>
                                <th style="width:30px"></th>
                                <th>Item Code</th>
                                <th>Item Name</th>
                                <th>Qty</th>
                                <th>UOM</th>
                            </tr>
                        </thead>
                        <tbody>${items}</tbody>
                    </table>
                `
            },
            {
                label: 'Target Company',
                fieldname: 'target_company',
                fieldtype: 'Link',
                options: 'Company',
                reqd: 1,
                get_query: () => {
                    return {
                        filters: [
                            ["name", "!=", frm.doc.company]
                        ]
                    };
                },
                onchange: function() {
                    let company = d.get_value('target_company');
                    if (company) {
                        d.set_df_property('target_warehouse', 'reqd', 1);
                        d.set_df_property('target_warehouse', 'read_only', 0);
                        d.fields_dict.target_warehouse.get_query = () => {
                            return {
                                filters: {
                                    company: company
                                }
                            };
                        };
                    }
                }
            },
            {
                label: 'Target Warehouse',
                fieldname: 'target_warehouse',
                fieldtype: 'Link',
                options: 'Warehouse',
                reqd: 0,
                read_only: 1
            }
        ],
        primary_action_label: 'Convert Selected Items',
        primary_action(values) {
            const selected_items = [];
            const wrapper = d.$body || d.$wrapper;  // ensures compatibility across Frappe versions
            $(wrapper)
                .find('.convert-check:checked')
                .each(function() {
                    selected_items.push($(this).data('item'));
                });
            
            console.log("Selected Items:", selected_items);

            if (!selected_items.length) {
                frappe.msgprint(__('Please select at least one item to convert.'));
                return;
            }

            d.hide();
            console.log("Target Company:", values.target_company);
            frappe.call({
                method: 'qcmc_logic.api.convertpr.convert_pr_to_partner',
                args: {
                    source_pr: frm.doc.name,
                    target_company: values.target_company,
                    target_warehouse: values.target_warehouse,
                    selected_items: JSON.stringify(selected_items) 
                },
                freeze: true,
                freeze_message: __('Converting PR...'),
                callback: function(r) {
                    if (!r.exc) {
                        frappe.msgprint(__('Partner PR Created: ') + r.message);
                        frm.reload_doc();
                    }
                }
            });
        }
    });

    d.show();
}

