                query: "qcmc_logic.MRFStaffingPlan.get_designations_from_custom_staffing_plan",
                filters: {
                    custom_staffing_plan: frm.doc.custom_staffing_plan,
                    custom_additional_manpower: frm.doc.custom_additional_manpower
