frappe.ui.form.on("Job Requisition", {
    refresh(frm) {
        // Update status when form is loaded or refreshed
        frm.trigger("update_status_based_on_workflow");
    },

    workflow_state(frm) {
        // Update status automatically when workflow state changes
        frm.trigger("update_status_based_on_workflow");
    },

    update_status_based_on_workflow(frm) {
        const state = frm.doc.workflow_state;
        let new_status = null;

        if (["Draft", "For Approval", "Approved", "For BCC Approval", "For VP Sales Approval", "For VP Procurement"].includes(state)) {
            new_status = "Pending";
        } 
        else if (["Acknowledged"].includes(state)) {
            new_status = "Open & Approved";
        } 
        else if (state === "Cancelled") {
            new_status = "Cancelled";
        }
        else if (state ==="Completed") {
            new_status = "Filled";
        }
        // Only update and save if status is changing
        if (new_status && frm.doc.status !== new_status) {
            frm.set_value("status", new_status);
            frm.set_value("completed_on", frappe.datetime.nowdate());
            frm.save_or_update(); // auto-save silently after status change
        }
    }
});

