// -----------------------------------------------
// Main formatting function
// -----------------------------------------------
function display_multiline_goals(frm) {
    const multiline_fields = ["custom_competency", "custom_kpi", "custom_targetmeasure"];
    const grid_field = frm.fields_dict["goals"];
    if (!grid_field) return;

    // Format cells with multiline text
    multiline_fields.forEach(fieldname => {
        grid_field.grid.wrapper.find(`div[data-fieldname="${fieldname}"]`).each(function() {
            const $cell = $(this);
            const $control = $cell.find(".control-value");

            // Skip if editing
            if ($cell.hasClass("editable")) return;

            const text = $control.length ? $control.text() : $cell.text();

            if (text && $cell.find("pre").length === 0) {
                $cell.html(
                    `<pre style="margin:0; white-space:pre-wrap; word-break:break-word; font-family:inherit; font-size: inherit;">${text}</pre>`
                );
            }
        });
    });

    // Expand rows after formatting
    expand_grid_rows(frm);
}

// -----------------------------------------------
// Expand entire row height based on content
// -----------------------------------------------
function expand_grid_rows(frm) {
    const grid = frm.fields_dict["goals"].grid;

    grid.grid_rows.forEach(row => {
        const $row = $(row.row);

        // Allow height to grow
        $row.css({
            "height": "auto",
            "min-height": "50px",
            "padding": "6px 0"
        });

        // Adjust cell containers
        $row.find("div.grid-static-col, div.grid-row").css({
            "height": "auto",
            "white-space": "normal",
            "line-height": "1.3em"
        });

        // Adjust content of the displayed values
        $row.find("pre, .control-value").css({
            "height": "auto",
            "white-space": "pre-wrap",
            "word-break": "break-word"
        });
    });
}

