// Helper to centralize the update trigger
function process_grade_update(frm) {
    frm.set_value("grade", null); 
    const salary = parse_currency(frm.doc.custom_monthly_salary || 0);
    set_employee_grade(frm, salary);
}

function bind_salary_input(frm) {
    const field = frm.fields_dict.custom_monthly_salary;
    if (!field || !field.$input) return;

    field.$input.off("input.salary_refresh");
    field.$input.on(
        "input.salary_refresh",
        frappe.utils.debounce(() => {
            const raw_value = field.$input.val() || "0";
            const salary = parse_currency(raw_value);

            // Update doc value and trigger grade logic
            frm.doc.custom_monthly_salary = salary;
            set_employee_grade(frm, salary);
        }, 500) // Increased slightly for better stability
    );
}

function parse_currency(value) {
    if (!value) return 0;
    // Remove commas and non-numeric except decimal point
    let clean_val = value.toString().replace(/,/g, "");
    return flt(clean_val, 2);
}

function set_employee_grade(frm, salary) {
    // Validation check
    if (!salary || salary <= 0 || !frm.doc.custom_location || !frm.doc.custom_employee_type) {
        return;
    }

    const rate_type = ["EDSA", "MULTI"].includes(frm.doc.custom_location) ? "NCR" : "PROV";

    get_grades(rate_type).then(grades => {
        if (!grades || !grades.length) return;

        const target_type = (frm.doc.custom_employee_type || "").trim();
        const salary_num = flt(salary, 2);

        let matching_grades = grades.filter(g => {
            const min = flt(g.custom_min1, 2);
            const max = flt(g.custom_max2, 2);
            const grade_emp_type = (g.custom_level_name || "").trim();

            // Strict decimal range comparison
            return (
                grade_emp_type === target_type &&
                salary_num >= min &&
                salary_num <= max
            );
        });

        if (matching_grades.length > 0) {
            // Sort by min1 descending to pick the most specific grade if ranges overlap
            matching_grades.sort((a, b) => flt(b.custom_min1, 2) - flt(a.custom_min1, 2));
            
            if (frm.doc.grade !== matching_grades[0].name) {
                frm.set_value("grade", matching_grades[0].name);
                frm.refresh_field("grade");
            }
        } else {
            frm.set_value("grade", null);
            frappe.show_alert({
                message: __("No Grade range found for {0} at {1} rate", [salary_num, rate_type]),
                indicator: "orange"
            });
        }
    });
}

function get_grades(rate_type) {
    if (grade_cache[rate_type]) return Promise.resolve(grade_cache[rate_type]);

    return frappe.db.get_list("Employee Grade", {
        fields: ["name", "custom_level_name", "custom_min1", "custom_max2", "custom_salary_rate_type"],
        filters: { custom_salary_rate_type: rate_type },
        limit: 200 // Ensure we get all relevant grades
    }).then(r => {
        grade_cache[rate_type] = r;
        return r;
    });
}

