// ─── Reverse geocode: lat/lon -> address string ───────────────────────────────
async function reverse_geocode(lat, lon) {
  try {
    const url = `https://nominatim.openstreetmap.org/reverse?` +
      `format=jsonv2&lat=${lat}&lon=${lon}&addressdetails=1`;
    const res = await fetch(url, { headers: { Accept: "application/json" } });
    if (!res.ok) return null;
    const data = await res.json();
    return data?.display_name || null;
  } catch (e) {
    console.warn("Reverse geocode failed:", e);
    return null;
  }
}

// ─── Apply lat/lon + GeoJSON to form ─────────────────────────────────────────
async function apply_location(frm, lat, lon, search_label) {
  if (frm.doc.latitude !== undefined) await frm.set_value("latitude", lat);
  if (frm.doc.longitude !== undefined) await frm.set_value("longitude", lon);

  const geojson = {
    type: "FeatureCollection",
    features: [{
      type: "Feature",
      properties: {},
      geometry: { type: "Point", coordinates: [lon, lat] }
    }]
  };

  await frm.set_value("location", JSON.stringify(geojson));
  frm.refresh_field("location");

  if (search_label) {
    await frm.set_value("custom_search", search_label);
    setTimeout(() => {
      const field = frm.fields_dict["custom_search"];
      if (field && field.$input) field.$input.val(search_label);
      frm.refresh_field("location");
    }, 250);
  }
}

// ─── Normalize query ──────────────────────────────────────────────────────────
function normalize_query(raw) {
  let q = raw.trim().replace(/\s+/g, " ");
  q = q.replace(/[,.]+$/, "").trim();
  return q;
}

function build_queries(raw) {
  const q = normalize_query(raw);
  const hasPH = /philippines|pilipinas/i.test(q);
  const queries = [];

  queries.push(hasPH ? q : `${q}, Philippines`);
  if (hasPH) queries.push(q.replace(/,?\s*(philippines|pilipinas)/i, "").trim());
  if (!q.includes(",")) queries.push(`${q}, Metro Manila, Philippines`);

  return [...new Set(queries)];
}

// ─── Source 1: Nominatim ──────────────────────────────────────────────────────
async function nominatim_search(q) {
  const url = `https://nominatim.openstreetmap.org/search?` +
    `format=jsonv2&addressdetails=1&limit=10&` +
    `viewbox=116.93,4.59,126.61,21.12&bounded=0&` +
    `q=${encodeURIComponent(q)}`;

  try {
    const res = await fetch(url, { headers: { Accept: "application/json" } });
    if (!res.ok) return [];
    const data = await res.json();
    return (data || []).map(r => ({
      display: r.display_name,
      lat: parseFloat(r.lat),
      lon: parseFloat(r.lon),
      importance: parseFloat(r.importance || 0),
      type: r.type || "",
      source: "nominatim"
    }));
  } catch (e) {
    console.warn("Nominatim error:", e);
    return [];
  }
}

// ─── Source 2: Photon (Komoot) ────────────────────────────────────────────────
async function photon_search(q) {
  const url = `https://photon.komoot.io/api/?` +
    `q=${encodeURIComponent(q)}&limit=10&lang=en&` +
    `lat=12.8797&lon=121.7740`;

  try {
    const res = await fetch(url, { headers: { Accept: "application/json" } });
    if (!res.ok) return [];
    const data = await res.json();
    return (data.features || []).map(f => {
      const p = f.properties || {};
      const country = (p.country || "").toLowerCase();
      if (country && country !== "philippines") return null;
      const parts = [p.name, p.street, p.housenumber, p.district, p.city, p.state, p.country]
        .filter(Boolean).join(", ");
      return {
        display: parts || p.name || "Unknown",
        lat: f.geometry.coordinates[1],
        lon: f.geometry.coordinates[0],
        importance: p.osm_type === "node" ? 0.3 : 0.5,
        type: p.osm_value || p.type || "",
        source: "photon"
      };
    }).filter(Boolean);
  } catch (e) {
    console.warn("Photon error:", e);
    return [];
  }
}

// ─── Rank results ─────────────────────────────────────────────────────────────
const TYPE_SCORE = {
  building: 1.0, house: 1.0, residential: 0.9,
  commercial: 0.9, amenity: 0.85, retail: 0.85,
  road: 0.7, street: 0.7, suburb: 0.6,
  village: 0.5, town: 0.5, city: 0.4,
  state: 0.3, country: 0.1
};

function rank_results(results) {
  return results.map(r => ({
    ...r,
    score: (r.importance || 0) + (TYPE_SCORE[r.type] || 0.4)
  })).sort((a, b) => b.score - a.score);
}

// ─── Combined geocode ─────────────────────────────────────────────────────────
async function geocode_query(raw) {
  const queries = build_queries(raw);
  const calls = [];
  for (const q of queries) {
    calls.push(nominatim_search(q));
    calls.push(photon_search(q));
  }

  const all_results = (await Promise.all(calls)).flat();
  const seen = new Set();
  const unique = [];
  for (const r of all_results) {
    const key = r.display.toLowerCase().trim();
    if (!seen.has(key)) { seen.add(key); unique.push(r); }
  }
  return rank_results(unique);
}

// ─── Autocomplete setup ───────────────────────────────────────────────────────
function setup_address_autocomplete(frm, fieldname) {
  const field = frm.fields_dict[fieldname];
  if (!field || !field.$input) return;
  if (field.__addr_autocomplete_bound) return;
  field.__addr_autocomplete_bound = true;

  const $input = field.$input;

  const aw = field.awesomplete || new Awesomplete($input.get(0), {
    minChars: 2,
    maxItems: 50,
    autoFirst: true,
    // ✅ Disable internal filter — we supply pre-filtered results from APIs
    filter: function() { return true; },
    item: function(text) {
      const li = document.createElement("li");
      li.textContent = text;
      li.setAttribute("aria-selected", "false");
      return li;
    }
  });
  field.awesomplete = aw;

  frappe.dom.set_style(`
    .awesomplete > ul {
      max-height: 400px !important;
      overflow-y: auto !important;
      z-index: 9999 !important;
    }
    .awesomplete > ul > li {
      white-space: normal !important;
      word-break: break-word !important;
      padding: 6px 10px !important;
      line-height: 1.4 !important;
      font-size: 13px !important;
    }
    .search-loading-indicator {
      font-size: 11px;
      color: #888;
      padding: 2px 4px;
      display: block;
    }
  `);

  const cache = new Map();
  const meta = new Map();

  const $loader = $('<span class="search-loading-indicator"></span>');
  $input.after($loader);

  const fetchSuggestions = frappe.utils.debounce(async () => {
    const raw = ($input.val() || "").trim();
    if (raw.length < 2) {
      aw.list = []; meta.clear(); $loader.text(""); return;
    }

    const cacheKey = raw.toLowerCase();
    if (cache.has(cacheKey)) {
      const { list, metaMap } = cache.get(cacheKey);
      aw.list = list;
      meta.clear();
      for (const [k, v] of metaMap) meta.set(k, v);
      aw.evaluate();
      $loader.text(`${list.length} result(s) found`);
      return;
    }

    $loader.text("⏳ Searching...");

    try {
      const results = await geocode_query(raw);
      meta.clear();
      const list = results.map(r => {
        meta.set(r.display, { lat: r.lat, lon: r.lon });
        return r.display;
      });

      cache.set(cacheKey, { list, metaMap: new Map(meta) });
      aw.list = list;
      aw.evaluate();
      $loader.text(list.length ? `${list.length} result(s) found` : "No results found");
    } catch (e) {
      console.warn("Autocomplete error:", e);
      $loader.text("Search error");
    }
  }, 400);

  $input.on("input", fetchSuggestions);

  $input.on("awesomplete-selectcomplete", async function (e) {
    const selected = e.originalEvent?.text?.value || $input.val();
    $loader.text("");

    const hit = meta.get(selected);
    if (!hit) {
      await frm.set_value(fieldname, selected);
      await frm.trigger("pin_from_address");
      return;
    }

    await apply_location(frm, hit.lat, hit.lon, selected);
    frm.dashboard.set_headline_alert("Pinned successfully ✅", "green");
    setTimeout(() => frm.dashboard.clear_headline(), 1500);
  });
}

