function open_update_dialog(frm) {
    const existing_items = frm.doc.transfer_items || [];
    let rows_html = '';

    existing_items.forEach((row, idx) => {
        rows_html += generate_row_html(row, idx, false);
    });

    const dialog = new frappe.ui.Dialog({
        title: 'Update Received Items',
        size: 'extra-large',
        fields: [
            {
                fieldname: 'items_table',
                label: 'Items',
                fieldtype: 'HTML'
            },
            {
                fieldname: 'add_row',
                fieldtype: 'Button',
                label: 'Add Row',
                click() {
                    const idx = $('.item-row').length;
                    const new_row_html = generate_row_html({}, idx, true);
                    $('#custom-items-table tbody').append(new_row_html);
                    init_link_fields(idx);
                }
            },
            {
                fieldname: 'delete_selected',
                fieldtype: 'Button',
                label: 'Delete Selected Rows',
                click() {
                    $('#custom-items-table tbody tr').each(function () {
                        const $tr = $(this);
                        const is_new = $tr.attr('data-new') === '1';
                        const is_checked = $tr.find('.row-checkbox').is(':checked');

                        if (is_new && is_checked) {
                            $tr.remove();
                        }
                    });
                }
            }
        ],
        primary_action_label: 'Save to Form',
        primary_action() {
            $('#custom-items-table tbody tr').each(function () {
                const $tr = $(this);
                const idx = cint($tr.attr('data-idx'));
                const is_new = $tr.attr('data-new') === '1';
        
                if (is_new) {
                    // Create a new row in child table
                    let child = frm.add_child('transfer_items');
                    child.item_code = $(`#item_code_input_${idx}`).val();
                    child.item_name = $tr.find('.item_name').text();
                    child.uom = $(`#uom_input_${idx}`).val();
                    child.issued_qty = flt($tr.find('.issued_qty').text());  // will be 0
                    child.received_qty = flt($tr.find('.received_qty').val());
                    child.reference_doc = $tr.find('.reference_doc').text();
                } else {
                    // Update existing row
                    const row = frm.doc.transfer_items[idx];
                    if (row) {
                        row.received_qty = flt($tr.find('.received_qty').val());
                    }
                }
            });
        
            frm.refresh_field('transfer_items');
            dialog.hide();
        }
    });

    const html = `
        <table class="table table-bordered" id="custom-items-table">
            <thead>
                <tr>
                    <th style="width:30px;"></th>
                    <th>Item Code</th>
                    <th>Item Name</th>
                    <th>UOM</th>
                    <th>Issued Qty</th>
                    <th>Received Qty</th>
                    <th>Variance</th>
                    <th>Reference Doc</th>
                </tr>
            </thead>
            <tbody>${rows_html}</tbody>
        </table>
    `;
    dialog.fields_dict.items_table.$wrapper.html(html);

    $('.item-row[data-new="1"]').each(function () {
        const idx = $(this).attr('data-idx');
        init_link_fields(idx);
    });

    dialog.$wrapper.on('input', '.received_qty', function () {
        const $tr = $(this).closest('tr');
        const issued = flt($tr.find('.issued_qty').text());
        const received = flt($(this).val());
        $tr.find('.variance').text((issued - received).toFixed(2));
    });

    dialog.show();
}

function generate_row_html(row, idx, is_new) {
    return `
        <tr class="item-row" data-idx="${idx}" data-new="${is_new ? 1 : 0}">
            <td>${is_new ? `<input type="checkbox" class="row-checkbox">` : ''}</td>
            <td>${is_new
                ? `<div id="item_code_${idx}" class="link-field-placeholder"></div>`
                : `<input type="text" class="form-control item_code" value="${frappe.utils.escape_html(row.item_code || '')}" readonly>`}</td>
            <td><span class="item_name text-ellipsis" title="${frappe.utils.escape_html(row.item_name || '')}" style="max-width:200px; display:inline-block; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${frappe.utils.escape_html(row.item_name || '')}</span></td>
            <td>${is_new
                ? `<div id="uom_${idx}" class="link-field-placeholder"></div>`
                : `<input type="text" class="form-control uom" value="${frappe.utils.escape_html(row.uom || '')}" readonly>`}</td>
            <td><span class="issued_qty">${flt(row.issued_qty || 0).toFixed(2)}</span></td>
            <td><input type="number" class="form-control received_qty" value="${flt(row.received_qty || 0)}"></td>
            <td><span class="variance">${flt((row.issued_qty || 0) - (row.received_qty || 0)).toFixed(2)}</span></td>
            <td><span class="reference_doc text-ellipsis" title="${frappe.utils.escape_html(row.reference_doc || '')}" style="max-width:200px; display:inline-block; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${frappe.utils.escape_html(row.reference_doc || '')}</span></td>
        </tr>
    `;
}

function init_link_fields(idx) {
    const item_code_field = frappe.ui.form.make_control({
        df: {
            fieldtype: 'Link',
            options: 'Item',
            fieldname: `item_code_input_${idx}`,
            placeholder: 'Item Code',
            change() {
                const item_code = item_code_field.get_value();
                if (item_code) {
                    frappe.db.get_doc('Item', item_code).then(doc => {
                        $(`.item-row[data-idx="${idx}"] .item_name`).text(doc.item_name);
                        $(`.item-row[data-idx="${idx}"] .reference_doc`).text('');
                        $(`.item-row[data-idx="${idx}"] .issued_qty`).text('0.00');
                        $(`.item-row[data-idx="${idx}"] .received_qty`).val('0');
                        $(`.item-row[data-idx="${idx}"] .variance`).text('0.00');

                        const uom_placeholder = $(`#uom_${idx}`);
                        uom_placeholder.empty();

                        frappe.ui.form.make_control({
                            df: {
                                fieldtype: 'Link',
                                options: 'UOM',
                                fieldname: `uom_input_${idx}`,
                                placeholder: 'UOM',
                                default: doc.stock_uom
                            },
                            parent: uom_placeholder,
                            render_input: true
                        }).set_value(doc.stock_uom);
                    });
                }
            }
        },
        parent: $(`#item_code_${idx}`),
        render_input: true
    });
}

