// helper function
function has_credit_role() {
    return frappe.user.has_role("Credit and Collection User") || frappe.user.has_role("Credit and Collection Section Head");
}

frappe.ui.form.on("Purchase Order", {
    onload: function(frm) {
        frm.trigger("set_naming_series");
    },

    company: function(frm) {
        frm.trigger("set_naming_series");
    },

    set_naming_series: function(frm) {
        if (!frm.doc.company) return;

        frappe.db.get_value("Company", frm.doc.company, "custom_doc_extension", function(r) {
            if (r && r.custom_doc_extension) {
                let ext = r.custom_doc_extension;

                // Define allowed series depending on extension
                let allowed_series = [];
                if (ext === "MCY" || ext === "QM") {
                    // Only basic series, no X
                    allowed_series = [`.${ext}.#`];
                } else if (ext === "Q" || ext === "M") {
                    // Allow both
                    allowed_series = [`.${ext}.#`, `.${ext}.X.#`];
                }

                // Set options dynamically
                frm.set_df_property("naming_series", "options", allowed_series.join("\n"));

                // Reset value only if current is not in allowed
                if (!allowed_series.includes(frm.doc.naming_series)) {
                    frm.set_value("naming_series", allowed_series[0]);
                }
            }
        });
    }
});

frappe.ui.form.on("Sales Order", {
    refresh: function(frm) {
        

        // Use the delay that worked in debug to ensure the DOM is ready
        setTimeout(() => {
            const po_field = frm.get_field("po_no");

            if (po_field && po_field.$input) {
                console.log("PO Duplicate Check: Attaching blur event to PO field.");

                po_field.$input.off("blur").on("blur", function() {
                    const current_val = $(this).val();
                    
                    // Only trigger if:
                    // 1. There is a value
                    // 2. A customer is selected
                    // 3. It's different from the last value we already checked/approved
                    if (current_val && frm.doc.customer && current_val !== frm.__last_checked_po) {
                        
                        check_duplicate_po(frm, current_val);
                    }
                });
            }
        }, 500);
    },

    // Also trigger if they change the customer AFTER typing a PO number
    customer: function(frm) {
        if (frm.doc.customer && frm.doc.po_no) {
            check_duplicate_po(frm, frm.doc.po_no);
        }
    }
});

function check_duplicate_po(frm, po_value) {
    frappe.call({
        method: "qcmc_logic.utils.check_duplicate_customer_po",
        args: {
            customer: frm.doc.customer,
            po_no: po_value,
            current_name: frm.doc.name
        },
        callback: function (r) {
            const duplicates = r.message || [];

            if (duplicates.length > 0) {
                

                const list = duplicates.slice(0, 5).join(', ');
                const msg = __(`
                    <b>Duplicate PO Detected</b><br><br>
                    Customer <b>{0}</b> has already used PO No. <b>{1}</b> in:<br>
                    <span style="color: #d63031; font-weight: bold;">{2}</span><br><br>
                    Do you want to proceed with this PO number?
                `, [frm.doc.customer, po_value, list]);

                frappe.confirm(
                    msg,
                    () => {
                        // YES: Remember this value so we don't prompt again for this specific entry
                        
                        frm.__last_checked_po = po_value;
                    },
                    () => {
                        // NO: Clear the field and reset the memory
                        
                        frm.set_value("po_no", "");
                        frm.__last_checked_po = "";
                        
                        // Refocus so they can type a new one immediately
                        setTimeout(() => {
                            if (frm.fields_dict.po_no && frm.fields_dict.po_no.$input) {
                                frm.fields_dict.po_no.$input.trigger("focus");
                            }
                        }, 300);
                    }
                );
            } else {
                // No duplicates found: store this as the "last checked" to prevent redundant calls
                
                frm.__last_checked_po = po_value;
            }
        }
    });
}
